var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"늦어서 죄송합니다. 굽이 그만 바닥에 걸려서 예상보다 조금 지체됐네요.","JPN":"遅れて申し訳ありません。ヒールが地面に引っかかって、予想より少し遅くなってしまいましたわ。","ENG":"Sorry I'm late. My heel caught on something, and I ended up more delayed than I thought."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"긴장을 자주하는 성격이라 이런 일에는 종종 실수를 저지르곤 해서 곤란하단 말이죠.","JPN":"緊張しやすい性格なので、こういった時によくしくじってしまい苦労しております。","ENG":"I get nervous easily, so I tend to mess up in situations like this. It's kind of a problem."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그래서 말인데… 계약에 관해서는 다시 생각해주시면 안 될까요?","JPN":"それでですが……契約については考え直してもらえませんか？","ENG":"So... about that contract. Would you consider giving it some more thought?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"저를 좋게 평가해주시는 건 감사하지만 역시, 아직은 자신이 없달까…….","JPN":"私を高く評価していただくのはありがたいのですが、やはりまだ自信がないというか……","ENG":"I appreciate the high praise, but I don't exactly have the confidence to back it up..."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"네? 실수해도 괜찮으니 자신을 가지라고요?","JPN":"はい？　失敗してもいいから自信を持て？","ENG":"Huh? You're saying it's okay to make mistakes, and be more confident?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"..."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하아, 당신. 에둘러 거절을 표현하고 있으면 알아서 물러나야 하는 거 아니에요?","JPN":"はあ、あなたねえ。遠回しに断っているのですから、いい加減諦めたらどうです？","ENG":"*Sigh Seriously, if someone's politely backing out, you should take the hint and let them go."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"집착이 심하면 인기도 없는 법이라고요. 얼굴 믿고 어디까지 막 나갈 셈인지, 원.","JPN":"執着しすぎてはモテないですわよ。顔がいいのをいいことに勝手するのにもほどがありますわ。","ENG":"Clinging too hard isn't exactly charming, you know. Just how far are you planning to push things with that face of yours?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아무튼. 전 어디 종신할 생각 없어요. 벌어놓은 돈도 많은데 제가 미쳤다고 일만 해요?","JPN":"とにかく。私はどの会社にも生涯勤める気なんてありません。稼いだお金も結構あるのに、何を好き好んで仕事ばかりするのです？","ENG":"Anyway, I'm not trying to be tied down forever. I've got savings, so why would I waste my life working?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"알아들었으면, 이번 계약은 없었던 걸로…….","JPN":"おわかりになったのなら、今回の契約はなかったことに……","ENG":"If we’re clear, then let's just pretend this contract never happened..."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"자, 잠시만. 왜 갑자기 손을 잡고 그래요? 이렇게 부탁해도 안 들어줄 거라고요?","JPN":"ちょ、ちょっと。なんですか、いきなり手を取って？　そうやって頼んでも無駄ですよ？","ENG":"W-wait a second. Why are you suddenly grabbing my hand? Even if you beg like this, I'm not going to change my mind."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그런 식으로 말해도… 아니, 그러니까 저는…….","JPN":"そんな風に言われても……いや、だから私は……","ENG":"Even if you say that... I mean, I..."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 알았어요. 알았으니까 손 좀 놔요! 하면 될 거 아니에요, 하면!","JPN":"わ、わかりました。わかりましたから、放してください！　やればいいんでしょう、やれば！","ENG":"F-fine. Just let go of my hand already! I'll do it, okay? I said I'll do it!"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"후우… 그래도 잊지 마세요. 제가 싫다는 걸 그쪽이 꼬드긴 셈이니까, 저한테 빚 하나 졌단 걸요.","JPN":"ふう……でもお忘れなく。私が嫌だと言ったのをそちらがしつこく頼み込んだわけですから、1つ借りを作ったことになります。","ENG":"Whew... But don't forget. You talked me into this. So technically, you owe me one."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"저도 다음에 무리한 부탁 하나 할 거니까, 이번 빚은 그때 제대로 충당하셔야 한답니다?","JPN":"私も今度無理なお願いを1つしますから、今回の貸しはその時にきっちり埋め合わせてくださいね。","ENG":"I'll be making an unreasonable request next time, and you'd better be ready to pay that debt in full, all right?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"제 은퇴계획을 망가트리신 만큼, 제대로 곤란하게 해드릴 테니 각오하세요.","JPN":"私の引退計画を台無しにした分、しっかり困らせてあげますから、覚悟することです。","ENG":"You ruined my early retirement plan, so I'll make sure to cause you just as much trouble."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"네? 어떤 부탁을 할 생각이냐고요?","JPN":"えっ？　どんな頼みかって？","ENG":"Huh? What kind of favor am I planning?"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"..."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어떨 것 같아요?","JPN":"何だと思います？","ENG":"Take a guess."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};